"use strict";(globalThis.webpackChunkstandard=globalThis.webpackChunkstandard||[]).push([[3394],{8237(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","label":"Overview","href":"/standard/","docId":"index","unlisted":false},{"type":"link","label":"Introduction and Scope","href":"/standard/introduction/","docId":"introduction/index","unlisted":false},{"type":"link","label":"Fundamental Principles and Design Criteria","href":"/standard/principles/","docId":"principles/index","unlisted":false},{"type":"category","label":"Phonology","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Phonemic Inventory","href":"/standard/phonology/inventory","docId":"phonology/inventory","unlisted":false},{"type":"link","label":"Phonotactics","href":"/standard/phonology/phonotactics","docId":"phonology/phonotactics","unlisted":false},{"type":"link","label":"Stress and Prosody","href":"/standard/phonology/stress","docId":"phonology/stress","unlisted":false},{"type":"link","label":"Phonological Alternations and Morphophonology","href":"/standard/phonology/alternations","docId":"phonology/alternations","unlisted":false}],"href":"/standard/phonology/"},{"type":"category","label":"Orthography and Writing Systems","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Standard Latin and Cyrillic Orthography","href":"/standard/orthography/latin","docId":"orthography/latin","unlisted":false},{"type":"link","label":"Etymological (Scientific) Alphabet","href":"/standard/orthography/etymological","docId":"orthography/etymological","unlisted":false},{"type":"link","label":"Transliteration","href":"/standard/orthography/transliteration","docId":"orthography/transliteration","unlisted":false},{"type":"link","label":"Spelling Conventions","href":"/standard/orthography/spelling","docId":"orthography/spelling","unlisted":false}],"href":"/standard/orthography/"},{"type":"category","label":"Morphology","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Nouns","href":"/standard/morphology/nouns","docId":"morphology/nouns","unlisted":false},{"type":"link","label":"Adjectives","href":"/standard/morphology/adjectives","docId":"morphology/adjectives","unlisted":false},{"type":"link","label":"Adverbs","href":"/standard/morphology/adverbs","docId":"morphology/adverbs","unlisted":false},{"type":"link","label":"Pronouns","href":"/standard/morphology/pronouns","docId":"morphology/pronouns","unlisted":false},{"type":"link","label":"Numerals","href":"/standard/morphology/numerals","docId":"morphology/numerals","unlisted":false},{"type":"link","label":"Verbs","href":"/standard/morphology/verbs","docId":"morphology/verbs","unlisted":false},{"type":"link","label":"Prepositions","href":"/standard/morphology/prepositions","docId":"morphology/prepositions","unlisted":false},{"type":"link","label":"Conjunctions and Particles","href":"/standard/morphology/particles","docId":"morphology/particles","unlisted":false},{"type":"link","label":"Word Formation and Derivation","href":"/standard/morphology/derivation","docId":"morphology/derivation","unlisted":false}],"href":"/standard/morphology/"},{"type":"category","label":"Syntax","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Basic Clause Structure","href":"/standard/syntax/clause","docId":"syntax/clause","unlisted":false},{"type":"link","label":"Noun Phrase Structure","href":"/standard/syntax/np","docId":"syntax/np","unlisted":false},{"type":"link","label":"Coordination","href":"/standard/syntax/coordination","docId":"syntax/coordination","unlisted":false},{"type":"link","label":"Subordination","href":"/standard/syntax/subordination","docId":"syntax/subordination","unlisted":false},{"type":"link","label":"Relative Clauses","href":"/standard/syntax/relative","docId":"syntax/relative","unlisted":false},{"type":"link","label":"Question Formation","href":"/standard/syntax/questions","docId":"syntax/questions","unlisted":false},{"type":"link","label":"Negation","href":"/standard/syntax/negation","docId":"syntax/negation","unlisted":false},{"type":"link","label":"Special Clause Types","href":"/standard/syntax/special","docId":"syntax/special","unlisted":false}],"href":"/standard/syntax/"},{"type":"category","label":"Semantics and Pragmatics","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Tense, Aspect, and Mood","href":"/standard/semantics/tam","docId":"semantics/tam","unlisted":false},{"type":"link","label":"Lexical Semantics","href":"/standard/semantics/lexical","docId":"semantics/lexical","unlisted":false},{"type":"link","label":"Pragmatics","href":"/standard/semantics/pragmatics","docId":"semantics/pragmatics","unlisted":false}],"href":"/standard/semantics/"},{"type":"category","label":"Lexicon and Vocabulary Policy","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Lexicon and Vocabulary Policy","href":"/standard/lexicon/selection","docId":"lexicon/selection","unlisted":false}],"href":"/standard/lexicon/"},{"type":"category","label":"Flavorization","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Phonological Flavorization","href":"/standard/flavorization/phon","docId":"flavorization/phon","unlisted":false},{"type":"link","label":"Morphological Flavorization","href":"/standard/flavorization/morph","docId":"flavorization/morph","unlisted":false},{"type":"link","label":"Lexical Flavorization","href":"/standard/flavorization/lex","docId":"flavorization/lex","unlisted":false},{"type":"link","label":"Orthographic Flavorization","href":"/standard/flavorization/orth","docId":"flavorization/orth","unlisted":false}],"href":"/standard/flavorization/"},{"type":"category","label":"Appendices and Reference Materials","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Appendix 1: Noun Declension Reference Tables","href":"/standard/appendices/noun-tables","docId":"appendices/noun-tables","unlisted":false},{"type":"link","label":"Appendix 2: Verb Conjugation Reference Tables","href":"/standard/appendices/verb-tables","docId":"appendices/verb-tables","unlisted":false},{"type":"link","label":"Appendix 3: Preposition Reference","href":"/standard/appendices/prepositions","docId":"appendices/prepositions","unlisted":false},{"type":"link","label":"Appendix 4: Verbal Prefix Inventory","href":"/standard/appendices/prefixes","docId":"appendices/prefixes","unlisted":false},{"type":"link","label":"Appendix 5: Derivational Suffix and Affix Inventory","href":"/standard/appendices/affixes","docId":"appendices/affixes","unlisted":false},{"type":"link","label":"Glossary","href":"/standard/appendices/glossary","docId":"appendices/glossary","unlisted":false},{"type":"link","label":"False Friends Register","href":"/standard/appendices/false-friends","docId":"appendices/false-friends","unlisted":false},{"type":"link","label":"Sample Texts and Communication Scenarios","href":"/standard/appendices/samples","docId":"appendices/samples","unlisted":false},{"type":"link","label":"Bibliography and Normative References","href":"/standard/appendices/bibliography","docId":"appendices/bibliography","unlisted":false},{"type":"link","label":"A.10. Changelog and About This Specification","href":"/standard/appendices/changelog","docId":"appendices/changelog","unlisted":false}],"href":"/standard/appendices/"}]},"docs":{"appendices/affixes":{"id":"appendices/affixes","title":"Appendix 5: Derivational Suffix and Affix Inventory","description":"Consonant mutations before selected suffixesisv[-ji],isv[-ko],isv[-ny],isv[-sky],isv[-nik] and :isv[-ny]. Suffixes starting with -o- change to -e- after soft consonants.","sidebar":"docs"},"appendices/bibliography":{"id":"appendices/bibliography","title":"Bibliography and Normative References","description":"This appendix lists the normative references on which the Interslavic specification rests, followed by a classified bibliography of descriptive sources for the individual Slavic languages and for comparative and historical Slavic linguistics. Entries are grouped thematically and ordered alphabetically by author within each group. Citation style follows a modified Chicago author\u2013date convention.","sidebar":"docs"},"appendices/changelog":{"id":"appendices/changelog","title":"A.10. Changelog and About This Specification","description":"About This Specification","sidebar":"docs"},"appendices/false-friends":{"id":"appendices/false-friends","title":"False Friends Register","description":"A false friend (la\u017eny prijatelj) is a word that looks or sounds similar to a word in another Slavic language but differs substantially in meaning. Because Interslavic draws its vocabulary from the common Slavic stock, a learner who already knows one or more Slavic languages may occasionally misread an Interslavic word through the lens of their own language. This register documents the most consequential such pairs.","sidebar":"docs"},"appendices/glossary":{"id":"appendices/glossary","title":"Glossary","description":"The glossary provides definitions for technical terms used throughout the specification. Users unfamiliar with specific linguistic terminology are encouraged to refer to this section for clarification.","sidebar":"docs"},"appendices/index":{"id":"appendices/index","title":"Appendices and Reference Materials","description":"Paradigm tables, sample texts, glossary, bibliography, and changelog.","sidebar":"docs"},"appendices/noun-tables":{"id":"appendices/noun-tables","title":"Appendix 1: Noun Declension Reference Tables","description":"All paradigms shown in both scripts. Hard stems listed first; soft-stem variants in parentheses where they differ.","sidebar":"docs"},"appendices/prefixes":{"id":"appendices/prefixes","title":"Appendix 4: Verbal Prefix Inventory","description":"Prefixes attach primarily to verbs but may also modify nouns and adjectives. The base form of any prefixed verb is perfective; secondary imperfectives are derived from it.","sidebar":"docs"},"appendices/prepositions":{"id":"appendices/prepositions","title":"Appendix 3: Preposition Reference","description":"Prepositions grouped by governed case. Where a preposition governs multiple cases the alternation rule is noted.","sidebar":"docs"},"appendices/samples":{"id":"appendices/samples","title":"Sample Texts and Communication Scenarios","description":"This appendix presents annotated sample texts drawn from authentic Interslavic sources. Each entry provides the text in standard Latin orthography and an English translation. Brief grammar notes highlight features that recur across the Interslavic system.","sidebar":"docs"},"appendices/verb-tables":{"id":"appendices/verb-tables","title":"Appendix 2: Verb Conjugation Reference Tables","description":"Both scripts. Conj. I = consonant-stem / -aj- stems; Conj. II = -i- stems.","sidebar":"docs"},"flavorization/index":{"id":"flavorization/index","title":"Flavorization","description":"Interslavic is designed to occupy the centre of the Slavic linguistic space, offering solutions that serve the broadest possible range of Slavic speakers.","sidebar":"docs"},"flavorization/lex":{"id":"flavorization/lex","title":"Lexical Flavorization","description":"Lexical flavorization selects among documented Interslavic synonyms according to their regional distribution.","sidebar":"docs"},"flavorization/morph":{"id":"flavorization/morph","title":"Morphological Flavorization","description":"Morphological flavorization selects among documented inflectional and derivational variants of Interslavic to increase familiarity for speakers of a particular dialect area.","sidebar":"docs"},"flavorization/orth":{"id":"flavorization/orth","title":"Orthographic Flavorization","description":"Orthographic flavorization adapts the written form of an Interslavic text to resemble the conventions of a particular national orthography.","sidebar":"docs"},"flavorization/phon":{"id":"flavorization/phon","title":"Phonological Flavorization","description":"Phonological flavorization makes use of the etymological alphabet  \u2014 the set of optional letters whose standard pronunciation is fixed but whose realization varies historically across the Slavic dialect continuum.","sidebar":"docs"},"index":{"id":"index","title":"Overview","description":"The normative specification of Interslavic (Med\u017euslovjansky jezyk / \u041c\u0435\u0434\u0436\u0443\u0441\u043b\u043e\u0432\u0458\u0430\u043d\u0441\u043a\u044b \u0458\u0435\u0437\u044b\u043a) \u2014 a zonal auxiliary language constructed to be broadly intelligible to speakers of the Slavic language family without prior study.","sidebar":"docs"},"introduction/index":{"id":"introduction/index","title":"Introduction and Scope","description":"Sections through  (Normative status, Scope, and What this specification does not cover) are new specification framework content with no basis in the source material. The normative keyword definitions, module breakdown, and scope exclusions are not derived from any source.","sidebar":"docs"},"lexicon/index":{"id":"lexicon/index","title":"Lexicon and Vocabulary Policy","description":"This file has no direct source material in the original Interslavic documentation corpus. All content in this section requires expert review and committee validation before it can be considered authoritative.","sidebar":"docs"},"lexicon/selection":{"id":"lexicon/selection","title":"Lexicon and Vocabulary Policy","description":"This section specifies the normative principles governing word selection, the treatment of international vocabulary, the management of false cognates, the policy on calques and borrowings, and the criteria for neologism approval in Interslavic. All normative rules use the terms MUST, SHALL, SHOULD, and MAY as defined in RFC 2119.","sidebar":"docs"},"morphology/adjectives":{"id":"morphology/adjectives","title":"Adjectives","description":"This section specifies the inflection, short forms, possessive formation, and degrees of comparison of adjectives in Interslavic. All normative rules use the terms MUST, SHALL, SHOULD, and MAY as defined in RFC 2119.","sidebar":"docs"},"morphology/adverbs":{"id":"morphology/adverbs","title":"Adverbs","description":"This section specifies the formation, comparison, and use of adverbs in Interslavic. All normative rules use the terms MUST, SHALL, SHOULD, and MAY as defined in RFC 2119.","sidebar":"docs"},"morphology/derivation":{"id":"morphology/derivation","title":"Word Formation and Derivation","description":"This section specifies the productive morphological processes by which new words are formed in Interslavic: suffixation, prefixation, zero derivation, and compounding. All normative rules use the terms MUST, SHALL, SHOULD, and MAY as defined in RFC 2119.","sidebar":"docs"},"morphology/index":{"id":"morphology/index","title":"Morphology","description":"Interslavic morphology is founded on the common grammatical categories shared by the Slavic language family: grammatical gender, number, case, verbal aspect, tense, mood, and person.","sidebar":"docs"},"morphology/nouns":{"id":"morphology/nouns","title":"Nouns","description":"The source material does not use RFC 2119 terminology (MUST, SHALL, SHOULD, MAY). The normative framing throughout this document is an editorial addition not present in the original grammar description.","sidebar":"docs"},"morphology/numerals":{"id":"morphology/numerals","title":"Numerals","description":"The RFC 2119 normative framing (MUST, SHALL, SHOULD, MAY) is not present in the source material. The source uses informal language throughout. The RECOMMENDED and MUST claims in this introduction go beyond what the source states; the source simply says \\"it deserves recommendation to write digits instead of number words.\\"","sidebar":"docs"},"morphology/particles":{"id":"morphology/particles","title":"Conjunctions and Particles","description":"The RFC 2119 normative framing (MUST, SHALL, SHOULD, MAY) is an editorial addition. The source material does not use normative language or RFC 2119 terminology.","sidebar":"docs"},"morphology/prepositions":{"id":"morphology/prepositions","title":"Prepositions","description":"The source material does not use RFC 2119 normative language. The original text uses informal phrasing like \\"should only be used\\" rather than formal MUST/SHALL/SHOULD/MAY distinctions. The RFC 2119 framing below is an addition not present in the source.","sidebar":"docs"},"morphology/pronouns":{"id":"morphology/pronouns","title":"Pronouns","description":"This section specifies the forms, inflection, and usage rules for all pronominal categories in Interslavic. All normative statements use MUST, SHALL, SHOULD, and MAY as defined in RFC 2119.","sidebar":"docs"},"morphology/verbs":{"id":"morphology/verbs","title":"Verbs","description":"This section specifies the grammatical categories, conjugation classes, tense and mood systems, non-finite forms, and irregular verb paradigms for verbs in Interslavic. All normative rules use the terms MUST, SHALL, SHOULD, and MAY as defined in RFC 2119.","sidebar":"docs"},"orthography/etymological":{"id":"orthography/etymological","title":"Etymological (Scientific) Alphabet","description":"The Interslavic etymological alphabet \u2014 historically known as Nau\u010dny Med\u017euslovjansky (\\"Scientific Interslavic\\"), also informally called MS Plus or etimologi\u010dny pravopis (\\"etymological orthography\\") \u2014 is an OPTIONAL extension of the standard orthography.","sidebar":"docs"},"orthography/index":{"id":"orthography/index","title":"Orthography and Writing Systems","description":"Historical Context","sidebar":"docs"},"orthography/latin":{"id":"orthography/latin","title":"Standard Latin and Cyrillic Orthography","description":"Interslavic has two fully equivalent standard alphabets \u2014 one Latin-based and one Cyrillic-based \u2014 reflecting the historical division of Slavic writing traditions. Neither alphabet is based on any single national orthography; both were designed as compromises that are intuitively readable across the Slavic world and that permit straightforward, unambiguous transliteration between the two scripts. Published texts are encouraged to provide both Latin and Cyrillic versions so that readers on either side of the Latin\u2013Cyrillic boundary can engage with the text without difficulty.","sidebar":"docs"},"orthography/spelling":{"id":"orthography/spelling","title":"Spelling Conventions","description":"This section specifies the normative orthographic conventions for Standard Interslavic beyond the letter-by-letter correspondences already established in the relevant section The rules below apply equally to both the Latin and Cyrillic scripts unless a script is explicitly named.","sidebar":"docs"},"orthography/transliteration":{"id":"orthography/transliteration","title":"Transliteration","description":"Transliteration is the systematic, rule-governed conversion of text from the Latin script to the Cyrillic script, or vice versa, without reference to pronunciation rules beyond what the orthography itself encodes.","sidebar":"docs"},"phonology/alternations":{"id":"phonology/alternations","title":"Phonological Alternations and Morphophonology","description":"Inflection in Interslavic is kept as regular as possible.","sidebar":"docs"},"phonology/index":{"id":"phonology/index","title":"Phonology","description":"Sound system: phonemic inventory, phonotactics, stress, and phonological processes.","sidebar":"docs"},"phonology/inventory":{"id":"phonology/inventory","title":"Phonemic Inventory","description":"Interslavic is neither a national language, nor does it attempt to emulate one.","sidebar":"docs"},"phonology/phonotactics":{"id":"phonology/phonotactics","title":"Phonotactics","description":"Interslavic orthography is based on etymology rather than pronunciation, so consonant clusters arise that may appear unpronounceable to speakers of non-Slavic languages \u2014 for example, :isv[vozvr\u0161enje].","sidebar":"docs"},"phonology/stress":{"id":"phonology/stress","title":"Stress and Prosody","description":"Stress in Interslavic is free: no single fixed-position rule is imposed for all words.","sidebar":"docs"},"principles/index":{"id":"principles/index","title":"Fundamental Principles and Design Criteria","description":"Core Design Principles","sidebar":"docs"},"semantics/index":{"id":"semantics/index","title":"Semantics and Pragmatics","description":"This section specifies the semantic and pragmatic rules of Interslavic: how grammatical and lexical choices map onto meaning, how context shapes interpretation, and how speakers deploy language to perform social actions. The rules defined here apply to all standard written and spoken Interslavic regardless of flavorizational register.","sidebar":"docs"},"semantics/lexical":{"id":"semantics/lexical","title":"Lexical Semantics","description":"This file has no direct source material for verification. All content in this section requires expert review to confirm accuracy and consistency with established Interslavic standards.","sidebar":"docs"},"semantics/pragmatics":{"id":"semantics/pragmatics","title":"Pragmatics","description":"This file has no direct source material for fact-checking. The pragmatic rules, ISV example forms, and phrasebook entries below have not been verified against an authoritative reference and require expert review.","sidebar":"docs"},"semantics/tam":{"id":"semantics/tam","title":"Tense, Aspect, and Mood","description":"This section specifies the semantic interpretation of tense and aspect combinations, the interaction of aspect with negation and phase verbs, the system of modal expressions, and the treatment of evidentiality in Interslavic.","sidebar":"docs"},"syntax/clause":{"id":"syntax/clause","title":"Basic Clause Structure","description":"This section specifies the structural principles governing simple clauses in Interslavic: canonical constituent order, pragmatic deviations from that order, subject-verb agreement, pro-drop, and the syntax of existential sentences.","sidebar":"docs"},"syntax/coordination":{"id":"syntax/coordination","title":"Coordination","description":"This section specifies the syntactic rules governing coordination in Interslavic: the behavior of coordinating and correlative conjunctions, agreement in coordinated noun phrases, and the conditions under which material may be elided or gapped in the second conjunct.","sidebar":"docs"},"syntax/index":{"id":"syntax/index","title":"Syntax","description":"This section specifies the syntactic rules of Interslavic: the principles that govern how words combine into phrases, clauses, and sentences. The rules defined here apply to all standard written and spoken Interslavic regardless of flavorizational register.","sidebar":"docs"},"syntax/negation":{"id":"syntax/negation","title":"Negation","description":"This entire file lacks direct source material. The source file (grammar-syntax.md by Jan van Steenbergen) does not cover negation syntax. All rules, examples, and paradigms in this section are AI-generated extrapolations from general Slavic patterns and cannot be verified against the original Interslavic documentation.","sidebar":"docs"},"syntax/np":{"id":"syntax/np","title":"Noun Phrase Structure","description":"The primary source material for syntax (Jan van Steenbergen\'s grammar-syntax) contains only a brief note that \\"modifiers usually precede the noun\\" and that this is \\"the most neutral and the clearest way.\\" The vast majority of this document \u2014 including canonical modifier ordering, numeral case government, apposition rules, possessive adjective distribution, agreeing/non-agreeing modifier theory, sentence-to-NP transformations, and capitalization rules \u2014 has no basis in the provided source material and appears to be editorial elaboration.","sidebar":"docs"},"syntax/questions":{"id":"syntax/questions","title":"Question Formation","description":"This file has no dedicated source document for question syntax. The core examples in the relevant section and  can be partially verified against Jan van Steenbergen\'s syntax page (grammar-syntax.md), but the detailed rules and additional sections ( li-placement,  multiple wh-questions,  embedded questions) are elaborations without direct source backing.","sidebar":"docs"},"syntax/relative":{"id":"syntax/relative","title":"Relative Clauses","description":"This file has no direct source material in the original Interslavic grammar by Jan van Steenbergen. The source material covers relative pronoun forms (ktory, koj, i\u017ee) and their inflection (in the pronouns section), but does not address relative clause syntax, gap vs. resumptive pronoun strategies, long-distance extraction, or free relative clause structure. Most of the syntactic analysis in this file is likely AI-generated and should be reviewed by the committee.","sidebar":"docs"},"syntax/special":{"id":"syntax/special","title":"Special Clause Types","description":"This section specifies the syntax of special clause types in Interslavic that have distinctive structural properties: imperatives (direct commands, hortatives, and optatives); impersonal constructions (meteorological predicates, dative-experiencer constructions, modal impersonals); reflexive constructions and their three functions; and complement control (subject-control and object-control verbs).","sidebar":"docs"},"syntax/subordination":{"id":"syntax/subordination","title":"Subordination","description":"The majority of this document cannot be verified against the provided source material. The primary source (grammar-conjunctions.md) covers prepositions, not subordinating conjunctions or clause types. The secondary source (grammar-syntax.md) covers basic word order, questions, passive voice, and purpose clauses only. Sections on complement clauses, infinitival complements, tense correlation, conditionals, temporal clauses, concessive/adversative clauses, compound sentences, subordination connectors, and punctuation rules have no corresponding source material and may reflect the document author\'s synthesis rather than established Interslavic norms.","sidebar":"docs"}}}}')}}]);